actions.action:

def filterBody = new com.netgrif.application.engine.menu.domain.FilterBody()
filterBody.setTitle(new com.netgrif.application.engine.petrinet.domain.I18nString("Main"))
filterBody.setQuery("_exists_:processIdentifier")
filterBody.setType("Case")
filterBody.setAllowedNets([])
filterBody.setIcon("apps")
filterBody.setVisibility("private")
filterBody.setMetadata([:])

def menuItemBody = new com.netgrif.application.engine.menu.domain.MenuItemBody(
        "/",
        "main",
        filterBody.getTitle(),
        filterBody.getIcon()
)
def singleTaskViewBody = new com.netgrif.application.engine.menu.domain.configurations.TabbedSingleTaskViewBody()
def ticketViewBody = new com.netgrif.application.engine.menu.domain.configurations.TabbedTicketViewBody()
ticketViewBody.setChainedView(singleTaskViewBody)
menuItemBody.setAutoSelect(true)
menuItemBody.setView(ticketViewBody)

def menuItem = createOrIgnoreMenuItem(menuItemBody)

def dashboardItemBody = new com.netgrif.application.engine.menu.domain.dashboard.DashboardItemBody("main", menuItem.stringId, "apps", new com.netgrif.application.engine.petrinet.domain.I18nString("Main"), true)
dashboardItemBody.setMenuItems(menuItem.stringId)
dashboardItemBody.setActive(true)

def dashboardItem = createDashboardItem(dashboardItemBody)

def mainDashboardCase = findDashboardManagement("main_dashboard")

def dashboardManagementBody = new com.netgrif.application.engine.menu.domain.dashboard.DashboardManagementBody()
dashboardManagementBody.setDashboardItems([(dashboardItem.stringId): dashboardItem.title])

updateDashboardManagement(mainDashboardCase, dashboardManagementBody)
